import SpeakBtn from "../SpeakBtn";

export default function SentencesSection({ sentences, onDone, done }) {
  return (
    <div className="fade-in space-y-3">
      {sentences.map((s, i) => (
        <div key={i} className=" rounded-2xl p-4 flex items-start justify-between gap-3 hover:border-teal-100 transition-all">
          <div className="flex-1">
            <p className="text-sm font-bold text-slate-800">{s.en}</p>
            <p className="text-xs text-slate-400 mt-1">{s.bn}</p>
          </div>
          <SpeakBtn text={s.en} />
        </div>
      ))}
      {!done ? (
        <div className="flex justify-end mt-5">
          <button onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5">
            Mark as Done ✓
          </button>
        </div>
      ) : <p className="text-right text-green-700 font-bold text-sm mt-4">✓ Sentences completed!</p>}
    </div>
  );
}
